from quote_source import source_window
from replay_mirror import mirror_window


def test_source_accessor_uses_requested_symbol():
    source = {"XYZ": [{"bid": 10.0}], "DEFAULT": [{"bid": 1.0}]}
    assert source_window(source, "XYZ") == [{"bid": 10.0}]


def test_mirror_copies_source_and_replaces_stale_sink():
    source = {"XYZ": [{"bid": 10.0}, {"bid": 10.1}]}
    sink = {"XYZ": [{"bid": 1.0}]}
    assert mirror_window(source, sink, "XYZ") == 2
    assert sink["XYZ"] == source["XYZ"]
    assert sink["XYZ"] is not source["XYZ"]
